   pm.expect(pm.response.headers.get("Content-Type")).to.include("application/json");
});
// Validate if response has JSON Body 
pm.test("[POST]::/vacatures/matches - Response has JSON Body", function () {
    pm.response.to.have.jsonBody();
});
function removeEmptyObjectsAndArrays(obj) {
  if (Array.isArray(obj)) {
      return obj.map(removeEmptyObjectsAndArrays).filter(item => !(Array.isArray(item) && item.length === 0) && !(typeof item === 'object' && !Array.isArray(item) && Object.keys(item).length === 0));
  } else if (typeof obj === 'object' && obj !== null) {
      const newObj = {};
      for (const key in obj) {
          const value = removeEmptyObjectsAndArrays(obj[key]);
          if (!(Array.isArray(value) && value.length === 0) && !(typeof value === 'object' && !Array.isArray(value) && Object.keys(value).length === 0)) {
              newObj[key] = value;
          }
      }
      return newObj;
  }
  return obj;
}
// Check that the defined results are returned in the response
pm.test("[GET]::/vacatures/matches - Expected results are included", function() {
    const zoekresultaten = JSON.parse(pm.iterationData.get("vacature.zoekresultaten"))
    const expected = zoekresultaten.map(function(item) {
        delete item.idVacature;
        item = removeEmptyObjectsAndArrays(item);
        return item;
    });
    const observed = pm.response.json().matches.map(function(item) {
        delete item.vumID;
        item = removeEmptyObjectsAndArrays(item);
        return item;
    });
    pm.expect(expected.every(val => _.some(observed, val))).to.eql(true);
});
// Set vumID to request the configured details for the match
let vumid_lookup = new Map();
pm.collectionVariables.set("vumID", "");
pm.response.json().matches.forEach(function(item) {
        const vumid = item.vumID;
        delete item.vumID;
        item = removeEmptyObjectsAndArrays(item);
        vumid_lookup.set(vumid, item);
});
let match = JSON.parse(pm.iterationData.get("vacature.zoekresultaten"))[0];
delete match.idVacature;
vumid_lookup.forEach(function(val, key) {
    if (_.isEqual(val, match)) {
        pm.collectionVariables.set("vumID", key);
    }
});

